import { test as setup } from '@playwright/test';
import path from 'path';

const TEST_USER_PASSWORD = process.env.TEST_USER_PASSWORD!;

setup('super_admin', async ({ page }) => {
  await page.goto('/auth/signin');
  await page
    .locator('input[name="email"]')
    .fill('user1_super_admin@example.com');
  await page.locator('input[name="password"]').fill(TEST_USER_PASSWORD);
  await page.locator('button[type="submit"]').click();
  await page.waitForLoadState('networkidle');
  await page.context().storageState({
    path: path.join(__dirname, '../playwright/.auth/super_admin.json'),
  });
});

setup('team_admin', async ({ page }) => {
  await page.goto('/auth/signin');
  await page.locator('input[name="email"]').fill('adm1-team_a@example.com');
  await page.locator('input[name="password"]').fill(TEST_USER_PASSWORD);
  await page.locator('button[type="submit"]').click();
  await page.waitForLoadState('networkidle');
  await page.context().storageState({
    path: path.join(__dirname, '../playwright/.auth/team_admin.json'),
  });
});
